#!/usr/bin/env node
import { readFileSync, writeFileSync } from 'node:fs';
import path from 'node:path';

const repoRoot = process.cwd();
const ledgerPath = path.join(repoRoot, 'open-source/gnosis/THEOREM_LEDGER.md');
const reportPath = path.join(repoRoot, 'open-source/gnosis/DUPLICATE_LEAN_REFS.md');

function rowCells(line) {
  return line
    .split('|')
    .slice(1, -1)
    .map((cell) => cell.trim());
}

function rowId(cell) {
  const match = cell.match(/^`?([^`\s]+)`?$/u);
  return match?.[1] ?? null;
}

function leanReference(cells) {
  const joined = cells.join(' ');
  const theoremMatch = joined.match(/Lean theorem `([^`]+)` in `([^`]+)`/u);
  if (theoremMatch) {
    return {
      key: `theorem:${theoremMatch[1]}@${theoremMatch[2]}`,
      declaration: theoremMatch[1],
      file: theoremMatch[2],
      kind: 'theorem',
    };
  }

  const declarationMatch = joined.match(
    /Lean declaration `([^`]+)` in namespace `([^`]+)`.*?`([^`]+\.lean)`/u
  );
  if (declarationMatch) {
    const namespace = declarationMatch[2];
    const declaration =
      namespace === '(root)'
        ? declarationMatch[1]
        : `${namespace}.${declarationMatch[1]}`;
    return {
      key: `declaration:${declaration}@${declarationMatch[3]}`,
      declaration,
      file: declarationMatch[3],
      kind: 'declaration',
    };
  }

  return null;
}

function canonicalId(entries) {
  return entries.find((entry) => entry.id.startsWith('THM-GNOSIS-MATH-'))?.id ?? entries[0].id;
}

const rows = readFileSync(ledgerPath, 'utf8')
  .split('\n')
  .filter((line) => line.startsWith('|') && !line.includes('---'));

const references = new Map();
for (const line of rows) {
  const cells = rowCells(line);
  if (cells.length < 4) continue;
  const id = rowId(cells[0]);
  if (!id?.startsWith('THM-')) continue;
  const reference = leanReference(cells);
  if (!reference) continue;
  const entries = references.get(reference.key) ?? [];
  entries.push({ id, line, ...reference });
  references.set(reference.key, entries);
}

const duplicateGroups = [...references.values()]
  .filter((entries) => entries.length > 1)
  .sort((left, right) => left[0].file.localeCompare(right[0].file));

function duplicateIdCount(entries) {
  return new Set(entries.map((entry) => entry.id)).size - 1;
}

const lines = [
  '# Duplicate Lean References',
  '',
  'Parent: [Gnosis](./README.md)',
  '',
  'Generated by `node open-source/gnosis/scripts/audit-ledger-duplicate-lean-refs.mjs`.',
  '',
  'Rows are grouped when more than one theorem-ledger ID points at the same explicit Lean theorem or declaration reference.',
  '',
  '## Summary',
  '',
  `- Duplicate Lean reference groups: ${duplicateGroups.length}`,
  `- Duplicate theorem IDs beyond one canonical row: ${duplicateGroups.reduce((total, entries) => total + duplicateIdCount(entries), 0)}`,
  '',
  '## Duplicate Groups',
  '',
  '| Lean reference | Canonical ID | Duplicate IDs |',
  '|---|---|---|',
];

for (const entries of duplicateGroups) {
  const canonical = canonicalId(entries);
  const duplicates = entries
    .map((entry) => entry.id)
    .filter((id) => id !== canonical)
    .map((id) => `\`${id}\``)
    .join('<br>');
  const reference = `\`${entries[0].declaration}\` in \`${entries[0].file}\``;
  lines.push(`| ${reference} | \`${canonical}\` | ${duplicates} |`);
}

writeFileSync(reportPath, `${lines.join('\n')}\n`, 'utf8');
console.log(`Wrote ${path.relative(repoRoot, reportPath)}`);
console.log(`Duplicate groups: ${duplicateGroups.length}`);
